INSERT INTO `automation_email_templates` VALUES (1,'Terk Edilen Sepet - 1. Saat','İşleminizi sadece 2 dakikada tamamlayabilirsiniz!','Kaldığınız yerden devam etmek çok kolay.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Kaldığınız yerden satın alma işleminize devam ederek süreci kolay ve hızlı bir şekilde sonuçlandırabilirsiniz.</p><p>Devam etmek için aşağıdaki butona tıklayabilirsiniz:</p><p>Herhangi bir sorunuz olması durumunda size destek olmaktan memnuniyet duyarız.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Devam Et','{{cart_link}}','[\"first_name\",\"cart_link\",\"unsubscribe_link\"]','2026-04-09 20:06:18','2026-04-09 20:06:18'),(2,'Terk Edilen Sepet - 1. Gün','Aradığınız Çözümlere Ulaşmak İçin Son 1 Adım!','Başvurunuzu henüz tamamlamadınız.','Khilonfast','merhaba@khilonfast.com','<!DOCTYPE HTML PUBLIC \"-//W3C//DTD XHTML 1.0 Transitional //EN\" \"http://www.w3.org/TR/xhtml1/DTD/xhtml1-transitional.dtd\">\n<html xmlns=\"http://www.w3.org/1999/xhtml\" xmlns:v=\"urn:schemas-microsoft-com:vml\" xmlns:o=\"urn:schemas-microsoft-com:office:office\">\n<head>\n<!--[if gte mso 9]>\n<xml>\n  <o:OfficeDocumentSettings>\n    <o:AllowPNG/>\n    <o:PixelsPerInch>96</o:PixelsPerInch>\n  </o:OfficeDocumentSettings>\n</xml>\n<![endif]-->\n  <meta http-equiv=\"Content-Type\" content=\"text/html; charset=UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <meta name=\"x-apple-disable-message-reformatting\">\n  <!--[if !mso]><!--><meta http-equiv=\"X-UA-Compatible\" content=\"IE=edge\"><!--<![endif]-->\n  \n  \n    <style type=\"text/css\">\n      \n      @media only screen and (min-width: 520px) {\n        .u-row {\n          width: 500px !important;\n        }\n\n        .u-row .u-col {\n          vertical-align: top;\n        }\n\n        \n            .u-row .u-col-100 {\n              width: 500px !important;\n            }\n          \n      }\n\n      @media only screen and (max-width: 520px) 