dColor\":\"\",\"padding\":\"0px\",\"border\":{},\"borderRadius\":\"0px\",\"_meta\":{\"htmlID\":\"u_column_1\",\"htmlClassNames\":\"u_column\"},\"deletable\":true,\"locked\":false}}],\"values\":{\"displayCondition\":null,\"columns\":false,\"_styleGuide\":null,\"backgroundColor\":\"\",\"columnsBackgroundColor\":\"\",\"backgroundImage\":{\"url\":\"\",\"fullWidth\":true,\"repeat\":\"no-repeat\",\"size\":\"custom\",\"position\":\"center\",\"customPosition\":[\"50%\",\"50%\"]},\"padding\":\"0px\",\"anchor\":\"\",\"hideDesktop\":false,\"_meta\":{\"htmlID\":\"u_row_1\",\"htmlClassNames\":\"u_row\"},\"selectable\":true,\"draggable\":true,\"duplicatable\":true,\"deletable\":true,\"hideable\":true,\"locked\":false}}],\"headers\":[],\"footers\":[],\"values\":{\"_styleGuide\":null,\"popupPosition\":\"center\",\"popupDisplayDelay\":0,\"popupWidth\":\"600px\",\"popupHeight\":\"auto\",\"borderRadius\":\"10px\",\"contentAlign\":\"center\",\"contentVerticalAlign\":\"middle\",\"contentWidth\":\"500px\",\"fontFamily\":{\"label\":\"Arial\",\"value\":\"arial,helvetica,sans-serif\"},\"textColor\":\"#000000\",\"popupBackgroundColor\":\"#FFFFFF\",\"popupBackgroundImage\":{\"url\":\"\",\"fullWidth\":true,\"repeat\":\"no-repeat\",\"size\":\"cover\",\"position\":\"center\",\"customPosition\":[\"50%\",\"50%\"]},\"popupOverlay_backgroundColor\":\"rgba(0, 0, 0, 0.1)\",\"popupCloseButton_position\":\"top-right\",\"popupCloseButton_backgroundColor\":\"#DDDDDD\",\"popupCloseButton_iconColor\":\"#000000\",\"popupCloseButton_borderRadius\":\"0px\",\"popupCloseButton_margin\":\"0px\",\"popupCloseButton_action\":{\"name\":\"close_popup\",\"attrs\":{\"onClick\":\"document.querySelector(\'.u-popup-container\').style.display = \'none\';\"}},\"language\":{},\"backgroundColor\":\"#F7F8F9\",\"preheaderText\":\"\",\"linkStyle\":{\"body\":true,\"linkColor\":\"#0000ee\",\"linkHoverColor\":\"#0000ee\",\"linkUnderline\":true,\"linkHoverUnderline\":true},\"backgroundImage\":{\"url\":\"\",\"fullWidth\":true,\"repeat\":\"no-repeat\",\"size\":\"custom\",\"position\":\"center\",\"customPosition\":[\"50%\",\"50%\"]},\"accessibilityTitle\":\"\",\"_meta\":{\"htmlID\":\"u_body\",\"htmlClassNames\":\"u_body\"}}},\"schemaVersion\":24}',NULL,'Devam Et','{{cart_link}}','[]','2026-04-09 20:06:18','2026-04-09 20:51:16'),(3,'Terk Edilen Sepet - 3. Gün','Biz başlamaya hazırız! Ya siz?','Başvurunuzu henüz tamamlamadığınızı fark ettik.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Başvurunuzu henüz tamamlamadığınızı fark ettik.</p><p>Size en uygun çözümlerimizle iş süreçlerinizde fark yaratmaya başlamak için sabırsızlanıyoruz.</p><p>Başvurunuzu tamamlamak için aşağıdaki butona tıklayabilirsiniz:</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Devam Et','{{cart_link}}','[\"first_name\",\"cart_link\",\"unsubscribe_link\"]','2026-04-09 20:06:18','2026-04-09 20:06:18'),(4,'Terk Edilen Sepet - 1. Hafta','İşleminizi birlikte tamamlamak ister misiniz?','Size süreçle ilgili yardımcı olabiliriz.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Henüz tamamlamadığınızı gördüğümüz işlemleriniz için dilerseniz size süreçle ilgili yardımcı olabilir ve sorularınızı yanıtlayabiliriz.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Sorularınızı Gönderin','{{contact_link}}','[\"first_name\",\"cart_link\",\"contact_link\",\"unsubscribe_link\"]','2026-04-09 20:06:18','2026-04-09 20:06:18'),(5,'Terk Edilen Sepet - 1. Ay','khilonfast Çözümleri Hala Gündeminizde Mi?','Tamamlanmayı bekleyen bir işleminiz var.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Hala tamamlanmayı bekleyen bir işleminiz olduğunu size hatırlatmak istedik.</p><p>Eğer şu an doğru zaman değilse sizi anlıyoruz. Dilerseniz işleminize istediğiniz zaman devam edebilir ve avantajlardan yararlanmaya başlayabilirsiniz.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Devam Et','{{cart_link}}','[\"first_name\",\"cart_link\",\"unsubscribe_link\"]','2026-04-09 20:06:18','2026-04-09 20:06:18'),(6,'Terk Edilen Sepet - 3. Ay','khilonfast Çözümlerine Göz Atmak İster Misiniz?','Daha evvel ilgilendiğiniz çözümleri tekrar inceleyin.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Daha evvel ilgilendiğiniz {{service_name}} ile birlikte diğer khilonfast çözümlerini tekrar incelemek ister misiniz?</p><p>Eğer ihtiyaçlarınız farklılaştıysa, sizin için yeni bir plan oluşturabiliriz.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Yeni Plan Oluştur','{{cart_link}}','[\"first_name\",\"service_name\",\"cart_link\",\"unsubscribe_link\"]','2026-04-09 20:06:18','2026-04-09 20:06:18'),(7,'Aldı Kullanmadı - 1. Saat','khilonfast ile başlamak için son adım!','Formu doldurmanız sadece 2–3 dakikanızı alacak.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Satın aldığınız hizmet için başlangıç formunu henüz doldurmadığınızı fark ettik.</p><p>Başvurunuzu tamamlamak için son adımınız kaldı. Formu doldurmanız sadece 2–3 dakikanızı alacak ve hizmetiniz hemen devreye girecek.</p><p>Herhangi bir sorunuz olursa size yardımcı olmaktan memnuniyet duyarız.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Formu Doldur','{{form_link}}','[\"first_name\",\"form_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(8,'Aldı Kullanmadı - 1. Gün','Başlamak için çok heyecanlıyız!','Başvurunuzu tamamlamadan önce bazı bilgilere ihtiyacımız var.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Başvurunuzu tamamlamadan önce bazı bilgilere ihtiyacımız var. Bu bilgileri almadan ne yazık ki süreci başlatamıyoruz.</p><p>Formu doldurmak yalnızca birkaç dakikanızı alacak ve ardından {{service_name}} hizmetiniz aktif hale gelecek.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Formu Doldur','{{form_link}}','[\"first_name\",\"service_name\",\"form_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(9,'Aldı Kullanmadı - 4. Gün','Sürecinizi başlatmak için yardımınıza ihtiyacımız var ☹','Başvurunuzu henüz tamamlamadığınız için süreci başlatamadık.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Başvurunuzu henüz tamamlamadığınız için süreci başlatamadık. Formu doldurarak hemen adım atabilir ve {{service_name}} avantajlarından yararlanmaya başlayabilirsiniz.</p><p>Herhangi bir sorunuz varsa lütfen bizimle iletişime geçin.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Formu Doldur','{{form_link}}','[\"first_name\",\"service_name\",\"form_link\",\"contact_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(10,'Aldı Kullanmadı - 11. Gün','khilonfast hizmetiniz sizi bekliyor!','Başvurunuzu henüz tamamlamadığınız için hizmetiniz beklemededir.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Başvurunuzu henüz tamamlamadığınız için {{service_name}} hizmetiniz şu anda beklemededir.</p><p>İsterseniz süreci hızlıca tamamlayarak çözümlerimizden hemen faydalanmaya başlayabilirsiniz. Sizi bekliyoruz!</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Formu Doldur','{{form_link}}','[\"first_name\",\"service_name\",\"form_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(11,'Aldı Kullanmadı - 30. Gün','Hizmetinizi başlatamadık ☹','Başvurunuzu tamamlamadığınız için süreç başlamadı.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Başvurunuzu tamamlamadığınız için ne yazık ki {{service_name}} süreciniz başlamadı.</p><p><strong>Bilgilerinizi form üzerinden paylaşmazsanız hizmetiniz durdurulacaktır.</strong></p><p>Süreci başlatmak ve khilonfast fırsatlarından yararlanmaya devam etmek için aşağıdaki formu doldurabilirsiniz.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Formu Doldur','{{form_link}}','[\"first_name\",\"service_name\",\"form_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(12,'Aldı Kullanmadı - 60. Gün','khilonfast Fırsatlarından Yararlanmaya Devam Edin!','Başvurunuzu henüz tamamlamadınız.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Başvurunuzu henüz tamamlamadınız. Hizmetinizden kesintisiz faydalanmak için lütfen başlangıç formunu doldurun.</p><p>Formun doldurulması yalnızca birkaç dakikanızı alacak ve {{service_name}} hizmetiniz tekrar aktif hale gelecek.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Formu Doldur','{{form_link}}','[\"first_name\",\"service_name\",\"form_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(13,'Aldı Kullanmadı - 90. Gün','khilonfast Ayrıcalıkları Sizi Bekliyor!','Başvurunuzu tamamlamadığınız için hizmet erişiminiz durdurulmuştur.','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Başvurunuzu tamamlamadığınız için {{service_name}} hizmetinize erişiminiz durdurulmuştur.</p><p>Eğer şimdi devam etmek isterseniz, formu doldurarak hizmetinizi tekrar başlatabilirsiniz. Sizi tekrar aramızda görmekten mutluluk duyarız.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Hizmeti Yeniden Başlat','{{form_link}}','[\"first_name\",\"service_name\",\"form_link\",\"contact_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(14,'Aldı Kullanmadı - Reaktivasyon 1 (11. Ay)','Yeniden Başlamanın Tam Zamanı!','khilonfast hizmetinizi yeniden aktif hale getirmek ister misiniz?','Khilonfast','merhaba@khilonfast.com','<p>Merhaba {{first_name}},</p><p>Bir yıl öncesinde satın aldığınız {{service_name}} hizmetini hiç kullanmadınızı fark ettik.</p><p>khilonfast hizmetinizi yeniden aktif hale getirmek ister misiniz? Formu doldurarak avantajlardan tekrar yararlanmaya başlayabilirsiniz.</p><p>Saygılarımızla,<br>Khilonfast Ekibi</p>',NULL,NULL,'Formu Doldur','{{form_link}}','[\"first_name\",\"service_name\",\"form_link\",\"unsubscribe_link\"]','2026-04-09 21:02:42','2026-04-09 21:02:42'),(15,'Aldı Kullanmadı - Reaktivasyon 2 (11. Ay + 2 Hafta)','khilonfast\'e ka