INSERT INTO `cms_page_contents` VALUES (27,1,1,'{\"en\": {\"faqs\": [{\"answer\": \"Kayıt sonrası erişiminiz kısa sürede aktif edilir ve eğitim modüllerine hemen başlayabilirsiniz.\", \"question\": \"Eğitime erişim ne zaman açılır?\"}, {\"answer\": \"Program hem yönetici seviyesine hem de operasyon ekiplerine uygundur; strateji ve uygulama birlikte ele alınır.\", \"question\": \"Eğitim içeriği hangi seviyeye uygundur?\"}, {\"answer\": \"Evet. İçerik ekip içi kullanım için yapılandırılmıştır ve ortak çalışma akışı sağlar.\", \"question\": \"Kurumsal ekipler için uygun mu?\"}], \"hero\": {\"image\": \"/hero-image.png\", \"title\": \"Ödeme Sistemlerinde Büyüme Odaklı Pazarlama Eğitimi\", \"subtitle\": \"Büyüme Odaklı Pazarlama Eğitimi\", \"badgeText\": \"10+1 Modül Eğitim\", \"buttonLink\": \"#pricing\", \"buttonText\": \"Programa Katıl\", \"description\": \"Satış hunisi, değer önerisi ve ölçümleme odaklı uygulamalı içerik\"}, \"testimonial\": {\"role\": \"Program Mezunu\", \"quote\": \"Eğitim sonrası pazarlama ve satış ekiplerimizin dili aynılaştı; lead kalitesi ve kapanış oranları belirgin şekilde arttı.\", \"author\": \"khilonfast Katılımcısı\"}, \"videoShowcase\": {\"tag\": \"Eğitim Tanıtımı\", \"title\": \"Satışa Giden Yol için Uygulamalı Eğitim Programı\", \"videoUrl\": \"https://vimeo.com/1133021053?fl=pl&fe=cm\", \"description\": \"Pazarlama stratejisini hedef kitle, değer önerisi ve ölçümleme odaklı kuran bu program; ekiplerinizi satışa daha hızlı taşıyan sistematik bir yöntem sunar.\"}, \"pricingSection\": {\"tag\": \"Kayıt\", \"title\": \"Eğitim Programı\", \"description\": \"Eğitime katılarak ekibiniz için büyüme odaklı pazarlama sistemini kurun.\"}, \"featuresSection\": {\"tag\": \"Program İçeriği\", \"title\": \"Eğitimde Yer Alan Modüller\", \"features\": [{\"title\": \"Büyüme Odaklı Pazarlamaya Giriş: Satışa Giden Yolun Haritası\", \"description\": \"Büyüme odaklı pazarlamanın temel çerçevesini kurun ve satışa giden yolu haritalayın.\"}, {\"title\": \"Ödeme Sistemlerinde Hedef Kitle: Karar Verici ve Onaylayıcıyı Doğru Okumak\", \"description\": \"Ödeme sistemleri ekosisteminde karar verici ve onaylayıcı rolleri doğru ayrıştırın.\"}, {\"title\": \"Egzersiz: Hedef Kitle Sorunlarını Not Etmek\", \"description\": \"Hedef kitlenin sorunlarını sistematik biçimde not ederek içgörü üretin.\"}, {\"title\": \"Değer Önerisi: Ethos, Pathos, Logos ile Fark Yaratmak\", \"description\": \"Ethos, Pathos ve Logos yaklaşımıyla güçlü bir değer önerisi geliştirin.\"}, {\"title\": \"Değer Önerisini Sistematik Kurmak: Pain Point ve Rol Bazlı Mesaj\", \"description\": \"Pain point odaklı ve rol bazlı mesajlarla değer önerinizi sistematik hale getirin.\"}, {\"title\": \"Satış Hunisi: Mesajı Zaman, Mecra ve Aşamaya Göre Uyarlamak\", \"description\": \"Mesajınızı doğru zamanda, doğru mecrada ve doğru aşamada konumlandırın.\"}, {\"title\": \"Başlangıç Metrikleri: Büyümenin Sayısal Pusulası\", \"description\": \"Büyümeyi ölçmek için başlangıç metriklerini belirleyin ve takip modelini kurun.\"}, {\"title\": \"Pazarlamanın Üç Net Hedefi: Kazanmak, Derinleşmek, Korumak\", \"description\": \"Kazanım, derinleşme ve koruma ekseninde pazarlama hedeflerinizi netleştirin.\"}, {\"title\": \"Web Sitesi ile Büyümek: Web Sitesindeki Sayfaların Görevleri\", \"description\": \"Web sitesi sayfalarının rollerini netleştirerek dönüşüm akışını iyileştirin.\"}, {\"title\": \"Lead Sonrası Akış: Psikoloji, Zamanlama ve Çok Kanallı Temas\", \"description\": \"Lead sonrası süreçte psikoloji, zamanlama ve çok kanallı temas dengesini kurun.\"}, {\"title\": \"İlk Temastan Satışa: Etkili İletişim, İtiraz Yönetimi ve Takip\", \"description\": \"İlk temastan satış kapanışına kadar iletişim, itiraz yönetimi ve takibi yönetin.\"}], \"description\": \"Temelden uygulamaya uzanan, sahada uygulanabilir eğitim akışı.\"}}, \"tr\": {\"faqs\": [{\"answer\": \"Kayıt sonrası erişiminiz kısa sürede aktif edilir ve eğitim modüllerine hemen başlayabilirsiniz.\", \"question\": \"Eğitime erişim ne zaman açılır?\"}, {\"answer\": \"Program hem yönetici seviyesine hem de operasyon ekiplerine uygundur; strateji ve uygulama birlikte ele alınır.\", \"question\": \"Eğitim içeriği hangi seviyeye uygundur?\"}, {\"answer\": \"Evet. İçerik ekip içi kullanım için yapılandırılmıştır ve ortak çalışma akışı sağlar.\", \"question\": \"Kurumsal ekipler için uygun mu?\"}], \"hero\": {\"image\": \"/hero-image.png\", \"title\": \"Ödeme Sistemlerinde Büyüme Odaklı Pazarlama Eğitimi\", \"subtitle\": \"Büyüme Odaklı Pazarlama Eğitimi\", \"badgeText\": \"10+1 Modül Eğitim\", \"buttonLink\": \"#pricing\", \"buttonText\": \"Programa Katıl\", \"description\": \"Satış hunisi, değer önerisi ve ölçümleme odaklı uygulamalı içerik\"}, \"testimonial\": {\"role\": \"Program Mezunu\", \"quote\": \"Eğitim sonrası pazarlama ve satış ekiplerimizin dili aynılaştı; lead kalitesi ve kapanış oranları belirgin şekilde arttı.\", \"author\": \"khilonfast Katılımcısı\"}, \"videoShowcase\": {\"tag\": \"Eğitim Tanıtımı\", \"title\": \"Satışa Giden Yol için Uygulamalı Eğitim Programı\", \"videoUrl\": \"https://vimeo.com/1133021053?fl=pl&fe=cm\", \"description\": \"Pazarlama stratejisini hedef kitle, değer önerisi ve ölçümleme odaklı kuran bu program; ekiplerinizi satışa daha hızlı taşıyan sistematik bir yöntem sunar.\"}, \"pricingSection\": {\"tag\": \"Kayıt\", \"title\": \"Eğitim Programı\", \"description\": \"Eğitime katılarak ekibiniz için büyüme odaklı pazarlama sistemini kurun.\"}, \"featuresSection\": {\"tag\": \"Program İçeriği\", \"title\": \"Eğitimde Yer Alan Modüller\", \"features\": [{\"title\": \"Büyüme Odaklı Pazarlamaya Giriş: Satışa Giden Yolun Haritası\", \"description\": \"Büyüme odaklı pazarlamanın temel çerçevesini kurun ve satışa giden yolu haritalayın.\"}, {\"title\": \"Ödeme Sistemlerinde Hedef Kitle: Karar Verici ve Onaylayıcıyı Doğru Okumak\", \"description\": \"Ödeme sistemleri ekosisteminde karar verici ve onaylayıcı rolleri doğru ayrıştırın.\"}, {\"title\": \"Egzersiz: H