INSERT INTO `products` VALUES (1,'gtm-core','hizmetlerimiz/go-to-market-stratejisi/core','services/go-to-market-strategy/core','Go To Market - Core','Go To Market - Core','Pazara hızlı giriş yapmak, temel satış ve değer önerisi oluşturmak isteyen küçük ve orta ölçekli işletmeler için ideal.','Accelerate your market entry with data-driven strategies.',9900.00,'USD','service',1,'2026-02-03 11:43:01','2026-02-25 01:57:27','service',NULL,NULL,NULL,NULL,NULL,'Go To Market Strategy | khilonfast','Expert market entry strategies for rapid growth.',NULL,'/images/hizmetlerimiz/go-to-market-stratejisi/hero.png',NULL,NULL,NULL,'/images/hizmetlerimiz/go-to-market-stratejisi/hero.png'),(2,'gtm-growth','hizmetlerimiz/go-to-market-stratejisi/growth','services/go-to-market-strategy/growth','Go To Market - Growth','Go To Market - Growth','Gelişmiş bir dijital, içerik ve pazarlama otomasyonu, satış stratejisi ile büyümeyi hedefleyen orta ölçekli işletmeler için ideal.','360-degree digital presence management.',14900.00,'USD','service',1,'2026-02-03 11:43:01','2026-02-25 01:57:27','service',NULL,NULL,NULL,NULL,NULL,'Integrated Digital Marketing | khilonfast','Complete digital marketing solutions.',NULL,'/images/hizmetlerimiz/go-to-market-stratejisi/hero.png',NULL,NULL,NULL,'/images/hizmetlerimiz/go-to-market-stratejisi/hero.png'),(3,'gtm-ultimate','hizmetlerimiz/go-to-market-stratejisi/ultimate','services/go-to-market-strategy/ultimate','Go To Market - Ultimate','Go To Market - Ultimate','Kapsamlı strateji, marka kimliği ve satış hunisi tasarımıyla kalıcı rekabet avantajı isteyen firmalar için ideal.','AI-powered marketing automation.',29900.00,'USD','service',1,'2026-02-03 11:43:01','2026-02-25 01:57:27','service',NULL,NULL,NULL,NULL,NULL,'Maestro AI Marketing | khilonfast','Revolutionize your marketing with AI.',NULL,'/images/hizmetlerimiz/go-to-market-stratejisi/hero.png',NULL,NULL,NULL,'/images/hizmetlerimiz/go-to-market-stratejisi/hero.png'),(4,'b2b-training','egitimler/b2b-pazarlama-egitimi','trainings/b2b-marketing-training','B2B Pazarlama Eğitimi','B2B Marketing Training','Tüm modüllere ömür boyu erişim ve uygulamalı egzersizler.','Personalized customer journeys at scale.',5000.00,'TRY','training',1,'2026-02-03 11:43:01','2026-02-25 01:57:27','service',NULL,NULL,NULL,NULL,NULL,'Email Automation | khilonfast','Drive engagement with smart email campaigns.',NULL,'/hero-image.png',NULL,NULL,NULL,'/hero-image.png'),(5,'training-buyume-odakli-pazarlama','egitimler/buyume-odakli-pazarlama-egitimi','trainings/growth-focused-marketing-training','Büyüme Odaklı Pazarlama Eğitimi','Growth-Focused Marketing Training','khilonfast temel büyüme odaklı pazarlama eğitim programı.','khilonfast core training program for growth-focused marketing.',5000.00,'TRY','egitimler',1,'2026-02-18 08:30:22','2026-02-25 02:15:47','video_course',30,'https://vimeo.com/1045939223','Hedef Kitle ve Segmentasyon\nDeğer Önerisi ve Mesaj Kurgusu\nSatış Hunisi Tasarımı\nÖlçümleme ve Optimizasyon','10+1 structured training modules\nApplied tasks and practical examples\nSector-specific growth methodology\nPerformance measurement templates\nTeam-ready implementation structure',NULL,'SEO & Content Strategy | khilonfast','Data-backed SEO and content services.',NULL,'/hero-image.png','','',NULL,'/hero-image.png'),(6,'training-odeme-sistemlerinde-buyume','egitimler/odeme-sistemlerinde-buyume-odakli-pazarlama-egitimi','trainings/growth-focused-marketing-training-for-payment-systems','Ödeme Sistemlerinde Büyüme Odaklı Pazarlama Eğitimi','Growth-Focused Marketing Training for Payment Systems','Satış hunisi, değer önerisi ve ölçümleme odaklı uygulamalı içerik.','Applied curriculum focused on sales funnel design, value proposition, and performance measurement.',5000.00,'TRY','training',1,'2026-02-18 08:30:22','2026-02-25 02:15:47','video_course',NULL,NULL,'10+1 modül eğitim içeriği\nUygulamalı görev ve örnekler\nSektör odaklı büyüme yaklaşımı\nÖlçümleme şablonları\nEkip kullanımına uygun içerik yapısı','10+1 structured training modules\nApplied tasks and practical examples\nSector-specific growth methodology\nPerformance measurement templates\nTeam-ready implementation structure',NULL,'Marketing Analytics | khilonfast','Professional analytics and reporting.',NULL,'/hero-image.png',NULL,NULL,NULL,'/hero-image.png'),(7,'training-b2b-sektorunde-buyume','b2b-sektorunde-buyume-odakli-pazarlama-egitimi','trainings/growth-focused-marketing-training-for-b2b','B2B Sektöründe Büyüme Odaklı Pazarlama Eğitimi','Growth-Focused Marketing Training for the B2B Sector','B2B firmalar için pazarlama ve satış entegrasyonu eğitim seti.','A training set designed to align marketing and sales execution for B2B companies.',5000.00,'TRY','training',1,'2026-02-18 08:30:22','2026-02-25 02:15:47','video_course',NULL,NULL,'10+1 modül eğitim içeriği\nUygulamalı görev ve örnekler\nSektör odaklı büyüme yaklaşımı\nÖlçümleme şablonları\nEkip kullanımına uygun içerik yapısı','10+1 structured training modules\nApplied tasks and practical examples\nSector-specific growth methodology\nPerformance measurement templates\nTeam-ready implementation structure',NULL,NULL,NULL,NULL,'/hero-image.png',NULL,NULL,NULL,'/hero-image.png'),(8,'training-fintech-sektorunde-buyume','fintech-sektorunde-buyume-odakli-pazarlama-egitimi','trainings/growth-focused-marketing-training-for-fintech','Fintech Sektöründe Büyüme Odaklı Pazarlama Eğitimi','Growth-Focused Marketing Training for the Fintech Sector','Fintech odaklı büyüme stratejileri ve kanal optimizasyonu.','Fintech-specific growth strategies and channel optimization framework.',5000.00,'TRY','training',1,'2026-02-18 08:30:22','2026-02-25 02:15:47','video_course',NULL,NULL,'10+1 modül eğitim içeriği\nUygulamalı görev ve örnekler\nSektör odaklı büyüme yaklaşımı\nÖlçümleme şablonları\nEkip kullanımına uygun içerik yapısı','10+1 structured training modules\nApplied tasks and practical examples\nSector-specific growth methodology\nPerformance measurement tem